import React from 'react';
import { BrowserRouter, Route } from 'react-router-dom';
import './App.css';
import Content from './Content/Content';
import Header from './Header/Header';
import Friends from './Navbar/Friends/Friends';
import Navbar from './Navbar/Navbar';
import NavCard from './NavCard/NavCard';
import NavMassage from './NavMassage/NavMassage';
import NavMedia from './NavMedia/NavMedia';

const App = (props) => {

        return ( <
                BrowserRouter >
                <
                div className = 'app-wrapper' >
                <
                Header / >
                <
                Navbar / >
                <
                div className = 'app-wrapper-content' >
                <
                Route path = '/content'
                render = {
                    () => < Content state = { props.state.contentPage }
                    /> } / >
                    <
                    Route path = '/navmassage'
                    render = {
                        () => < NavMassage state = { props.state.messagesPage }
                        /> } / >
                        <
                        Route path = '/navcard'
                        render = {
                            () => < NavCard / > }
                        /> <
                        Route path = '/navmedia'
                        render = {
                            () => < NavMedia / > }
                        /> <
                        Route path = '/friends'
                        render = {
                            () => < Friends state = { props.state.friendsPage }
                            />}/ >
                            <
                            /div> <
                            /div> <
                            /BrowserRouter>
                        );
                    }

                    export default App;
